<?php require_once __DIR__.'/define.php'; $messages=[]; if(file_exists(APP_INSTALLED_FLAG)){ exit('Already installed. Delete .installed to reinstall.'); } try{ $server=new PDO('mysql:host='.DB_HOST.';charset=utf8mb4',DB_USER,DB_PASS,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]); $server->exec('CREATE DATABASE IF NOT EXISTS `'.str_replace('`','',DB_NAME).'` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci'); require_once __DIR__.'/db.php'; $sql=file_get_contents(__DIR__.'/schema.sql'); pdo()->exec($sql); foreach(['admin','student','librarian'] as $r) pdo()->prepare('INSERT IGNORE INTO roles(name) VALUES(?)')->execute([$r]); $roles=pdo()->query('SELECT name,id FROM roles')->fetchAll(PDO::FETCH_KEY_PAIR); $adminPass=password_hash('admin123',PASSWORD_DEFAULT); $libPass=password_hash('librarian123',PASSWORD_DEFAULT); pdo()->prepare('INSERT IGNORE INTO users(role_id,name,email,password,status) VALUES(?,?,?,?,"active")')->execute([$roles['admin'],'System Admin','admin@library.test',$adminPass]); pdo()->prepare('INSERT IGNORE INTO users(role_id,name,email,password,status) VALUES(?,?,?,?,"active")')->execute([$roles['librarian'],'Default Librarian','librarian@library.test',$libPass]); $libId=pdo()->lastInsertId(); if($libId) pdo()->prepare('INSERT IGNORE INTO librarians(user_id,employee_code) VALUES(?,?)')->execute([$libId,'LIB-001']); $themes=[['Cosmic Blue','cosmic-blue','#5ee7ff','#7c3aed'],['Neon Mint','neon-mint','#34d399','#06b6d4'],['Royal Purple','royal-purple','#a78bfa','#f472b6'],['Solar Gold','solar-gold','#f59e0b','#ef4444'],['Emerald Grid','emerald-grid','#10b981','#84cc16'],['Ruby Night','ruby-night','#fb7185','#dc2626'],['Ocean Glass','ocean-glass','#38bdf8','#2563eb'],['Cyber Lime','cyber-lime','#bef264','#22c55e'],['Amber Noir','amber-noir','#fbbf24','#111827'],['Ice Silver','ice-silver','#e5e7eb','#94a3b8']]; foreach($themes as $t) pdo()->prepare('INSERT IGNORE INTO themes(name,slug,primary_color,accent_color) VALUES(?,?,?,?)')->execute($t); for($i=1;$i<=48;$i++) pdo()->prepare('INSERT IGNORE INTO library_tables(table_code,floor_no,zone,capacity,status) VALUES(?,?,?,?,"available")')->execute(['T'.str_pad($i,2,'0',STR_PAD_LEFT),ceil($i/16),chr(64+ceil($i/16)),1]); touch(APP_INSTALLED_FLAG); $messages[]='Installation complete. Admin: admin@library.test / admin123; Librarian: librarian@library.test / librarian123'; }catch(Throwable $e){ $messages[]='Error: '.$e->getMessage(); } ?><!doctype html><title>Installer</title><link rel="stylesheet" href="assets/css/style.css"><main class="container"><section class="card"><h1>Installer</h1><?php foreach($messages as $m):?><p><?=htmlspecialchars($m)?></p><?php endforeach;?><a class="btn" href="login.php">Login</a></section></main>
